/// <summary>
/// The <c>ETG_InventFairValueContract</c> class is the data contract 
/// </summary>
[DataContractAttribute]
[SysOperationContractProcessing(classStr(ETG_InventFairValueUIBuilder))]
  //  SysOperationGroup('ItemGroup','itemId', '1')

class ETG_InventFairValueContract
{
       ItemId                           ItemId;
       TransDate                        CurDate;
       DateOnhand                       PerDate;
       NoYes                            config,size,color,style,site , warehouse,location,batchnumber,serialNumber; //inventorystatus,licenseplate,serialnumber,owner;
       ETG_InventFairValueHeaderTable   inventFairValueHeaderTable;
       ETGVertical                      vertical;
       ETGSubVertical                   subVertical;
       ETGCommodity                     commodity;
       ETGSubCommodity                  subCommodity;
}

