    return inventFairValueHeaderTable;
}

   [
DataMemberAttribute('PerDate'),
SysOperationLabelAttribute(literalStr("@ETG_New:Date")),
SysOperationDisplayOrderAttribute('1')
]
public DateOnhand parmPerDate(DateOnhand _PerDate = PerDate)
{   
    PerDate = inventFairValueHeaderTable.ValuationDate;
    if(PerDate == dateNull() ||_PerDate == dateNull())
    {
        PerDate = _PerDate;
    }
    if(_PerDate < PerDate)
    {
        PerDate = _PerDate;
    }
    return PerDate;
}

